import React, { Component } from 'react'
import ModelReading from "../../components/models/ModelReading";
import ReadingContext from '../../contexts/ReadingContext';

class Reading extends Component {

    static contextType = ReadingContext;

    state = {
      readings : this.context,
    }

    render() {

        const sortedReadings = this.state.readings.sort(function(a, b){
            var x = a.level.toLowerCase();
            var y = b.level.toLowerCase();
            if (x < y) {return -1;}
            if (x > y) {return 1;}
            return 0;
        });

        return (
        <div class="container">
            <div class="row mt-5 mb-5">
                <div class="col-md-9">
                    
                    <div class="accordion accordion-flush" id="accordionFlushExample">

                        {sortedReadings.map(readingItem => (
                            <ModelReading db={readingItem}></ModelReading>
                        ))}

                    </div>

                </div>
                <div className="col-md-3">

                </div>
            </div>
        </div>
        )
    }
}

export default Reading;