import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import AnimalContext from '../../contexts/AnimalContext';

class LearnAnimals extends Component {

  static contextType = AnimalContext;

  state = {
      animals : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.animals} category="New Animal" />
        )
    }
}

export default LearnAnimals;