import React, { Component } from 'react'
import ConnectTheAntonymsContext from '../../contexts/ConnectTheAntonymsContext';
import ModelConnectTheAntonyms from '../models/ModelConnectTheAntonyms'

class ConnectTheAntonymsExercises extends Component {

    static contextType = ConnectTheAntonymsContext;

    state = {
        connectTheAntonymsExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9">

                        <div className="tab-content">

                            {/* a1-aggettivi-1 */}
                            <div className="tab-pane fade show active" id="a1-aggettivi-1">
                                <ModelConnectTheAntonyms db={this.state.connectTheAntonymsExercises.aggettivi1} />
                            </div>

                            {/* a1-aggettivi-2 */}
                            <div className="tab-pane fade" id="a1-aggettivi-2">
                                <ModelConnectTheAntonyms db={this.state.connectTheAntonymsExercises.aggettivi2} />
                            </div>

                            {/* a1-aggettivi-3 */}
                            <div className="tab-pane fade" id="a1-aggettivi-3">
                                <ModelConnectTheAntonyms db={this.state.connectTheAntonymsExercises.aggettivi3} />
                            </div>

                            {/* a1-aggettivi-4 */}
                            <div className="tab-pane fade" id="a1-aggettivi-4">
                                <ModelConnectTheAntonyms db={this.state.connectTheAntonymsExercises.aggettivi4} />
                            </div>

                        </div>   

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>LEVEL A1</h2>
                            <hr />
                            {/* a1-aggettivi-1 */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#a1-aggettivi-1">{this.state.connectTheAntonymsExercises.aggettivi1.title}</a>

                            {/* a1-aggettivi-2 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-aggettivi-2">{this.state.connectTheAntonymsExercises.aggettivi2.title}</a>

                            {/* a1-aggettivi-3 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-aggettivi-3">{this.state.connectTheAntonymsExercises.aggettivi3.title}</a>

                            {/* a1-aggettivi-4 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#a1-aggettivi-4">{this.state.connectTheAntonymsExercises.aggettivi4.title}</a>

                            <h2 className="mt-5">LEVEL A2</h2>
                            <hr />

                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default ConnectTheAntonymsExercises;