import React, { Component } from 'react'
import parse from 'html-react-parser';

class ModelReading extends Component {

    state = {
        id : this.props.db.id,
        level : this.props.db.level,
        title : this.props.db.title,
        text : this.props.db.text
    }

    render() {
        return (
        <div class="accordion-item">
            <h2 class="accordion-header">
                <button class="accordion-button collapsed" type="button" data-mdb-toggle="collapse"
                    data-mdb-target={"#" + this.state.id} >
                    {this.state.level} -- {this.state.title}
                </button>
            </h2>
            <div id={this.state.id} class="accordion-collapse collapse">
                <div class="accordion-body">
                    {parse(this.state.text)}
                </div>
            </div>
        </div>
        )
    }
}

export default ModelReading;